&reftitle.description;
floatround intfloatsayı inthassasiyet0 intRoundingModekipRoundingMode::HalfAwayFromZero
sayı değerini, belirtilen hassasiyet (ondalık noktadan sonraki basamak sayısı) düzeyinde yuvarlanmış olarak döndürür. hassasiyet negatif veya sıfır (öntanımlı) olabilir.

&reftitle.returnvalues;


 Belirtilen hassasiyet ile yuvarlanmış değer
 &float; olarak.

  &reftitle.examples;



    round örnekleri


<?php
var_dump(round(3.4));
var_dump(round(3.5));
var_dump(round(3.6));
var_dump(round(3.6, 0));
var_dump(round(5.045, 2));
var_dump(round(5.055, 2));
var_dump(round(345, -2));
var_dump(round(345, -3));
var_dump(round(678, -2));
var_dump(round(678, -3));
?>


    &example.outputs;


float(3)
float(4)
float(4)
float(4)
float(5.05)
float(5.06)
float(300)
float(0)
float(700)
float(1000)







    hassasiyet bir gerçek sayıyı nasıl etkiler


<?php
$sayı = 135.79;

var_dump(round($sayı, 3));
var_dump(round($sayı, 2));
var_dump(round($sayı, 1));
var_dump(round($sayı, 0));
var_dump(round($sayı, -1));
var_dump(round($sayı, -2));
var_dump(round($sayı, -3));
?>


    &example.outputs;


float(135.79)
float(135.79)
float(135.8)
float(136)
float(140)
float(100)
float(0)







    kip örnekleri


<?php
echo '9.5 ile yuvarlama kipleri' . PHP_EOL;
var_dump(round(9.5, 0, PHP_ROUND_HALF_UP));
var_dump(round(9.5, 0, PHP_ROUND_HALF_DOWN));
var_dump(round(9.5, 0, PHP_ROUND_HALF_EVEN));
var_dump(round(9.5, 0, PHP_ROUND_HALF_ODD));

echo PHP_EOL;
echo '8.5 ile yuvarlama kipleri' . PHP_EOL;
var_dump(round(8.5, 0, PHP_ROUND_HALF_UP));
var_dump(round(8.5, 0, PHP_ROUND_HALF_DOWN));
var_dump(round(8.5, 0, PHP_ROUND_HALF_EVEN));
var_dump(round(8.5, 0, PHP_ROUND_HALF_ODD));
?>


    &example.outputs;


9.5 ile yuvarlama kipleri
float(10)
float(9)
float(10)
float(9)

8.5 ile yuvarlama kipleri
float(9)
float(8)
float(8)
float(9)







    1 ondalık basamak hassasiyet ile kip örnekleri


<?php
echo 'PHP_ROUND_HALF_UP ile 1 ondalık basamak hassasiyet' . PHP_EOL;
var_dump(round( 1.55, 1, PHP_ROUND_HALF_UP));
var_dump(round(-1.55, 1, PHP_ROUND_HALF_UP));

echo PHP_EOL;
echo 'PHP_ROUND_HALF_DOWN ile 1 ondalık basamak hassasiyet' . PHP_EOL;
var_dump(round( 1.55, 1, PHP_ROUND_HALF_DOWN));
var_dump(round(-1.55, 1, PHP_ROUND_HALF_DOWN));

echo PHP_EOL;
echo 'PHP_ROUND_HALF_EVEN ile 1 ondalık basamak hassasiyet' . PHP_EOL;
var_dump(round( 1.55, 1, PHP_ROUND_HALF_EVEN));
var_dump(round(-1.55, 1, PHP_ROUND_HALF_EVEN));

echo PHP_EOL;
echo 'PHP_ROUND_HALF_ODD ile 1 ondalık basamak hassasiyet' . PHP_EOL;
var_dump(round( 1.55, 1, PHP_ROUND_HALF_ODD));
var_dump(round(-1.55, 1, PHP_ROUND_HALF_ODD));
?>


    &example.outputs;


PHP_ROUND_HALF_UP ile 1 ondalık basamak hassasiyet
float(1.6)
float(-1.6)

PHP_ROUND_HALF_DOWN ile 1 ondalık basamak hassasiyet
float(1.5)
float(-1.5)

PHP_ROUND_HALF_EVEN ile 1 ondalık basamak hassasiyet
float(1.6)
float(-1.6)

PHP_ROUND_HALF_ODD ile 1 ondalık basamak hassasiyet
float(1.5)
float(-1.5)




   RoundingMode kullanım örneği


<?php
foreach (RoundingMode::cases() as $kip) {
    foreach ([
        8.5,
        9.5,
        -3.5,
    ] as $sayı) {
        printf("%-17s: %+.17g -> %+.17g\n", $kip->name, $sayı, round($sayı, 0, $kip));
    }
    echo "\n";
}
?>


   &example.outputs;


HalfAwayFromZero : +8.5 -> +9
HalfAwayFromZero : +9.5 -> +10
HalfAwayFromZero : -3.5 -> -4

HalfTowardsZero  : +8.5 -> +8
HalfTowardsZero  : +9.5 -> +9
HalfTowardsZero  : -3.5 -> -3

HalfEven         : +8.5 -> +8
HalfEven         : +9.5 -> +10
HalfEven         : -3.5 -> -4

HalfOdd          : +8.5 -> +9
HalfOdd          : +9.5 -> +9
HalfOdd          : -3.5 -> -3

TowardsZero      : +8.5 -> +8
TowardsZero      : +9.5 -> +9
TowardsZero      : -3.5 -> -3

AwayFromZero     : +8.5 -> +9
AwayFromZero     : +9.5 -> +10
AwayFromZero     : -3.5 -> -4

NegativeInfinity : +8.5 -> +8
NegativeInfinity : +9.5 -> +9
NegativeInfinity : -3.5 -> -4

PositiveInfinity : +8.5 -> +9
PositiveInfinity : +9.5 -> +10
PositiveInfinity : -3.5 -> -3
